import xml.etree.ElementTree as ET
from collections import defaultdict


def parse(file):
    tree = ET.parse(file)

    root = tree.getroot()
    result = defaultdict(dict)
    
    for child in root:
        result[child.tag] = child.text
        
    return dict(result)

